class Solution {
    public int shortestMatchingSubstring(String s, String p) {
        int n = s.length(), m = p.length();
        int[] starIndex = new int[2];
        int cnt = 0;
        for (int i = 0; i < m; i++) {
            if (p.charAt(i) == '*') {
                starIndex[cnt++] = i;
            }
        }

        int res = n + 1;
        for (int i = 0; i <= n - (m - starIndex[1] + starIndex[0]); i++) {
            if (match(s, p, i, starIndex)) {
                res = Math.min(res, i + starIndex[1] - starIndex[0]);
            }
        }
        return res == n + 1 ? -1 : res;
    }

    private boolean match(String s, String p, int start, int[] starIndex) {
        int sIndex = start, pIndex = 0;
        while (pIndex < starIndex[0]) {
            if (sIndex >= s.length() || s.charAt(sIndex++) != p.charAt(pIndex++)) {
                return false;
            }
        }

        int sStarIndex = sIndex;
        while (pIndex < starIndex[1]) {
            if (sIndex >= s.length() || s.charAt(sIndex++) != p.charAt(pIndex++)) {
                return false;
            }
        }

        while (sIndex < s.length() && pIndex < p.length()) {
            if (s.charAt(sIndex++) != p.charAt(pIndex++)) {
                return false;
            }
        }

        return pIndex == p.length();
    }
}
